"""matplotlib.lines — Line2D stub."""


class Line2D:
    """Stub Line2D for API compatibility."""

    lineStyles = {'-': 'solid', '--': 'dashed', '-.': 'dashdot', ':': 'dotted'}
    markers = {'o': 'circle', 's': 'square', '^': 'triangle_up', 'v': 'triangle_down',
               'D': 'diamond', 'x': 'x', '+': 'plus', '*': 'star'}

    def __init__(self, xdata, ydata, **kwargs):
        self._x = xdata
        self._y = ydata
        self._color = kwargs.get('color', None)
        self._linewidth = kwargs.get('linewidth', 1.5)
        self._linestyle = kwargs.get('linestyle', '-')
        self._marker = kwargs.get('marker', None)
        self._label = kwargs.get('label', '')
        self._alpha = kwargs.get('alpha', None)

    def get_xdata(self): return self._x
    def get_ydata(self): return self._y
    def get_color(self): return self._color
    def get_linewidth(self): return self._linewidth
    def get_linestyle(self): return self._linestyle
    def get_marker(self): return self._marker
    def get_label(self): return self._label
    def set_xdata(self, x): self._x = x
    def set_ydata(self, y): self._y = y
    def set_color(self, c): self._color = c
    def set_linewidth(self, w): self._linewidth = w
    def set_linestyle(self, s): self._linestyle = s
    def set_marker(self, m): self._marker = m
    def set_label(self, l): self._label = l
    def set_alpha(self, a): self._alpha = a
    def set_data(self, x, y): self._x, self._y = x, y
    def set_visible(self, v): pass
    def remove(self): pass
